class Solution(object):
    def maximumTotalSum(self, maximumHeight):
        maximumHeight.sort(reverse=True)
        total = maximumHeight[0]
        prev = maximumHeight[0]
        for i in range(1, len(maximumHeight)):
            curr = min(maximumHeight[i], prev - 1)
            if curr <= 0:
                return -1
            total += curr
            prev = curr
        return total
